{
  "sentences": [
    {
      "text": "我昨天起床了，然後刷牙了。",
      "pinyin": "Wǒ zuótiān qǐchuáng le, ránhòu shuāyá le.",
      "pinyin_numeric": "wo3 zuo2tian1 qi3chuang2 le0, ran2hou4 shua1ya2 le0.",
      "translation_en": "I got up yesterday, and then brushed my teeth.",
      "translation_ko": "저는 어제 일어났고, 그다음에 이를 닦았어요."
    },
    {
      "text": "我昨天吃早餐了，然後出門了。",
      "pinyin": "Wǒ zuótiān chī zǎocān le, ránhòu chūmén le.",
      "pinyin_numeric": "wo3 zuo2tian1 chi1 zao3can1 le0, ran2hou4 chu1men2 le0.",
      "translation_en": "I ate breakfast yesterday, and then went out.",
      "translation_ko": "저는 어제 아침을 먹었고, 그다음에 외출했어요."
    },
    {
      "text": "我昨天上班了，然後下班了。",
      "pinyin": "Wǒ zuótiān shàngbān le, ránhòu xiàbān le.",
      "pinyin_numeric": "wo3 zuo2tian1 shang4ban1 le0, ran2hou4 xia4ban1 le0.",
      "translation_en": "I went to work yesterday, and then got off work.",
      "translation_ko": "저는 어제 출근했고, 그다음에 퇴근했어요."
    },
    {
      "text": "我昨天看電視了，然後睡覺了。",
      "pinyin": "Wǒ zuótiān kàn diànshì le, ránhòu shuìjiào le.",
      "pinyin_numeric": "wo3 zuo2tian1 kan4 dian4shi4 le0, ran2hou4 shui4jiao4 le0.",
      "translation_en": "I watched TV yesterday, and then went to sleep.",
      "translation_ko": "저는 어제 텔레비전을 봤고, 그다음에 잤어요."
    },
    {
      "text": "我昨天買菜了，然後煮飯了。",
      "pinyin": "Wǒ zuótiān mǎi cài le, ránhòu zhǔ fàn le.",
      "pinyin_numeric": "wo3 zuo2tian1 mai3 cai4 le0, ran2hou4 zhu3 fan4 le0.",
      "translation_en": "I bought groceries yesterday, and then cooked rice.",
      "translation_ko": "저는 어제 장을 봤고, 그다음에 밥을 지었어요."
    },
    {
      "text": "我昨天散步了，然後回家了。",
      "pinyin": "Wǒ zuótiān sànbù le, ránhòu huí jiā le.",
      "pinyin_numeric": "wo3 zuo2tian1 san4bu4 le0, ran2hou4 hui2 jia1 le0.",
      "translation_en": "I took a walk yesterday, and then went home.",
      "translation_ko": "저는 어제 산책했고, 그다음에 집에 돌아갔어요."
    },
    {
      "text": "我昨天洗澡了，然後穿衣服了。",
      "pinyin": "Wǒ zuótiān xǐzǎo le, ránhòu chuān yīfu le.",
      "pinyin_numeric": "wo3 zuo2tian1 xi3zao3 le0, ran2hou4 chuan1 yi1fu0 le0.",
      "translation_en": "I took a shower yesterday, and then got dressed.",
      "translation_ko": "저는 어제 샤워했고, 그다음에 옷을 입었어요."
    },
    {
      "text": "我昨天聽音樂了，然後看書了。",
      "pinyin": "Wǒ zuótiān tīng yīnyuè le, ránhòu kàn shū le.",
      "pinyin_numeric": "wo3 zuo2tian1 ting1 yin1yue4 le0, ran2hou4 kan4 shu1 le0.",
      "translation_en": "I listened to music yesterday, and then read a book.",
      "translation_ko": "저는 어제 음악을 들었고, 그다음에 책을 읽었어요."
    },
    {
      "text": "我昨天運動了，然後休息了。",
      "pinyin": "Wǒ zuótiān yùndòng le, ránhòu xiūxi le.",
      "pinyin_numeric": "wo3 zuo2tian1 yun4dong4 le0, ran2hou4 xiu1xi0 le0.",
      "translation_en": "I exercised yesterday, and then rested.",
      "translation_ko": "저는 어제 운동했고, 그다음에 쉬었어요."
    },
    {
      "text": "我昨天打掃了，然後整理房間了。",
      "pinyin": "Wǒ zuótiān dǎsǎo le, ránhòu zhěnglǐ fángjiān le.",
      "pinyin_numeric": "wo3 zuo2tian1 da3sao3 le0, ran2hou4 zheng3li3 fang2jian1 le0.",
      "translation_en": "I cleaned yesterday, and then tidied up the room.",
      "translation_ko": "저는 어제 청소했고, 그다음에 방을 정리했어요."
    }
  ]
}
